export const name='Embed Optimizer';const loadedElementContentRects=new Map();export async function initialize({log:_log}){const log=_log||console.log;const embedWrappers=document.querySelectorAll('.wp-block-embed > .wp-block-embed__wrapper[data-od-xpath]');for(const embedWrapper of embedWrappers){monitorEmbedWrapperForResizes(embedWrapper,log);}
log('Loaded embed content rects:',loadedElementContentRects);}
export async function finalize({log:_log,error:_error,getElementData,extendElementData,}){const log=_log||console.log;const error=_error||console.error;for(const[xpath,domRect]of loadedElementContentRects.entries()){try{extendElementData(xpath,{resizedBoundingClientRect:domRect,});const elementData=getElementData(xpath);log(`boundingClientRect for ${ xpath } resized:`,elementData.boundingClientRect,'=>',domRect);}catch(err){error(`Failed to extend element data for ${ xpath } with resizedBoundingClientRect:`,domRect,err);}}}
function monitorEmbedWrapperForResizes(embedWrapper,log){if(!('odXpath'in embedWrapper.dataset)){throw new Error('Embed wrapper missing data-od-xpath attribute.');}
const xpath=embedWrapper.dataset.odXpath;const observer=new ResizeObserver((entries)=>{const[entry]=entries;loadedElementContentRects.set(xpath,entry.contentRect);log(`Resized element ${ xpath }:`,entry.contentRect);});observer.observe(embedWrapper,{box:'content-box'});}